package com.nemu.jgridworld;

import javax.swing.*;
import java.awt.*;
import java.awt.image.BufferedImage;
import java.io.IOException;
import java.util.Base64;
import java.util.HashMap;
import java.util.Map;

public class Images {
    private static final String titleBarIconBase64 = "";
    private static final String questionMarkBase64 = "";
    private static final String exclamationMarkBase64 = "";
    private static final String cardinalArrowsBase64 = "";
    private static final String kingArrowsBase64 = "";
    private static final String lightBlueSelectedBase64 = "";
    private static final String darkBlueSelectedBase64 = "";
    private static final String purpleSelectedBase64 = "";
    private static final String redSelectedBase64 = "";
    private static final String orangeSelectedBase64 = "";
    private static final String yellowSelectedBase64 = "";
    private static final String greenSelectedBase64 = "";
    private static final String themeDecidesBase64 = "";
    private static final String themeDecidesSelectedBase64 = "";
    private static final Map<Color, ImageIcon> plainColorIconCache = new HashMap<>();
    public static final Image TITLE_BAR_ICON;
    public static final ImageIcon QUESTION_MARK;
    public static final ImageIcon EXCLAMATION_MARK;
    public static final ImageIcon CARDINAL_ARROWS;
    public static final ImageIcon KING_ARROWS;
    public static final ImageIcon LIGHT_BLUE_ICON;
    public static final ImageIcon DARK_BLUE_ICON;
    public static final ImageIcon PURPLE_ICON;
    public static final ImageIcon RED_ICON;
    public static final ImageIcon ORANGE_ICON;
    public static final ImageIcon YELLOW_ICON;
    public static final ImageIcon GREEN_ICON;
    public static final ImageIcon LIGHT_BLUE_SELECTED;
    public static final ImageIcon DARK_BLUE_SELECTED;
    public static final ImageIcon PURPLE_SELECTED;
    public static final ImageIcon RED_SELECTED;
    public static final ImageIcon ORANGE_SELECTED;
    public static final ImageIcon YELLOW_SELECTED;
    public static final ImageIcon GREEN_SELECTED;
    public static final ImageIcon THEME_DECIDES;
    public static final ImageIcon THEME_DECIDES_SELECTED;


    static {
        try {
            TITLE_BAR_ICON = javax.imageio.ImageIO.read(new java.io.ByteArrayInputStream(Base64.getDecoder().decode(titleBarIconBase64)));
            QUESTION_MARK = new ImageIcon(javax.imageio.ImageIO.read(new java.io.ByteArrayInputStream(Base64.getDecoder().decode(questionMarkBase64))));
            EXCLAMATION_MARK = new ImageIcon(javax.imageio.ImageIO.read(new java.io.ByteArrayInputStream(Base64.getDecoder().decode(exclamationMarkBase64))));
            CARDINAL_ARROWS = new ImageIcon(javax.imageio.ImageIO.read(new java.io.ByteArrayInputStream(Base64.getDecoder().decode(cardinalArrowsBase64))));
            KING_ARROWS = new ImageIcon(javax.imageio.ImageIO.read(new java.io.ByteArrayInputStream(Base64.getDecoder().decode(kingArrowsBase64))));
            LIGHT_BLUE_ICON = getOrCreatePlainColorIcon(78, 157, 231);
            DARK_BLUE_ICON = getOrCreatePlainColorIcon(0, 122, 255);
            PURPLE_ICON = getOrCreatePlainColorIcon(191, 90, 242);
            RED_ICON = getOrCreatePlainColorIcon(255, 59, 48);
            ORANGE_ICON = getOrCreatePlainColorIcon(255, 149, 0);
            YELLOW_ICON = getOrCreatePlainColorIcon(255, 204, 0);
            GREEN_ICON = getOrCreatePlainColorIcon(40, 205, 65);
            LIGHT_BLUE_SELECTED = new ImageIcon(javax.imageio.ImageIO.read(new java.io.ByteArrayInputStream(Base64.getDecoder().decode(lightBlueSelectedBase64))));
            DARK_BLUE_SELECTED = new ImageIcon(javax.imageio.ImageIO.read(new java.io.ByteArrayInputStream(Base64.getDecoder().decode(darkBlueSelectedBase64))));
            PURPLE_SELECTED = new ImageIcon(javax.imageio.ImageIO.read(new java.io.ByteArrayInputStream(Base64.getDecoder().decode(purpleSelectedBase64))));
            RED_SELECTED = new ImageIcon(javax.imageio.ImageIO.read(new java.io.ByteArrayInputStream(Base64.getDecoder().decode(redSelectedBase64))));
            ORANGE_SELECTED = new ImageIcon(javax.imageio.ImageIO.read(new java.io.ByteArrayInputStream(Base64.getDecoder().decode(orangeSelectedBase64))));
            YELLOW_SELECTED = new ImageIcon(javax.imageio.ImageIO.read(new java.io.ByteArrayInputStream(Base64.getDecoder().decode(yellowSelectedBase64))));
            GREEN_SELECTED = new ImageIcon(javax.imageio.ImageIO.read(new java.io.ByteArrayInputStream(Base64.getDecoder().decode(greenSelectedBase64))));
            THEME_DECIDES = new ImageIcon(javax.imageio.ImageIO.read(new java.io.ByteArrayInputStream(Base64.getDecoder().decode(themeDecidesBase64))));
            THEME_DECIDES_SELECTED = new ImageIcon(javax.imageio.ImageIO.read(new java.io.ByteArrayInputStream(Base64.getDecoder().decode(themeDecidesSelectedBase64))));
        }
        catch (IOException e) {
            throw new RuntimeException("Failed to build image store", e);
        }
    }

    public static synchronized ImageIcon getOrCreatePlainColorIcon(int r, int g, int b) {
        Color color = new Color(r, g, b);
      
      
        return plainColorIconCache.computeIfAbsent(color, c -> {
            BufferedImage image = new BufferedImage(16, 16, BufferedImage.TYPE_INT_RGB);
            Graphics2D gfx = image.createGraphics();
            try {
                gfx.setColor(c);
                gfx.fillRect(0, 0, 16, 16);
            } finally {
                gfx.dispose();
            }
            return new ImageIcon(image);
        });
    }

    public Images() {}
}
